def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0 or item <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 1.0
        decay = 0.95
        for j in range(1, 8):
            factor = j * utilization
            if factor < 0.2:
                score += np.exp(-factor) * (j ** 0.5)
            elif 0.2 <= factor < 0.5:
                score += np.tan(factor * np.pi / 4) * j
            elif 0.5 <= factor < 0.8:
                score += np.log1p(factor) * (j ** 1.5)
            else:
                score += (factor ** 2) / (j + 1)
            if j % 3 == 0:
                score *= (1 - 0.05 * j) * decay
                decay *= 0.9
        if item < 0.3:
            if bin_capacity > item * 5:
                for x in range(3):
                    score += (np.sin(x + utilization) + np.cos(x / (utilization + 0.1))) * 0.1
                score *= 1.15
            else:
                score *= 0.85
        elif 0.3 <= item <= 1.0:
            if bin_capacity < item * 2:
                for m in range(1, 5):
                    score += (np.cosh(m * utilization) / (m + 1)) * 0.2
                score *= 1.25
            elif bin_capacity > item * 7:
                score *= 0.65
            else:
                for n in range(2, 6):
                    score += np.tanh(n * utilization) / (n ** 0.5)
        else:
            limit = max(1, int(bin_capacity // item))
            for k in range(1, limit + 1):
                val = np.log(k + utilization + 1)
                if val % 2 < 1:
                    score += val ** 1.3
                else:
                    score += val / 2
            if bin_capacity < item * 4:
                score *= 1.4
            else:
                score *= 1.1
        if score < 0:
            score = abs(score) + 2
        if score > 10:
            score = 10 + np.log1p(score - 10)
        priorities[i] = score
    return priorities
